import{_ as t,o as i,c as o,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Process & Data","description":"","frontmatter":{"title":"Process & Data"},"headers":[],"relativePath":"docs/fr/advertisers/co-branded-contest/workflow.md","filePath":"docs/fr/advertisers/co-branded-contest/workflow.md"}'),s={name:"docs/fr/advertisers/co-branded-contest/workflow.md"};function n(a,e,d,l,c,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="workflow-du-jeu-concours" tabindex="-1">Workflow du Jeu Concours <a class="header-anchor" href="#workflow-du-jeu-concours" aria-label="Permalink to &quot;Workflow du Jeu Concours&quot;">​</a></h1><p>Ce dispositif nécessite une coordination précise pour la gestion des données personnelles (RGPD) et l&#39;activation commerciale.</p><hr><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3>Brief &amp; Définition de l&#39;offre</h3><p>Vous devez fournir les éléments suivants via la plateforme :</p><ul><li><strong>Les Lots :</strong> La carotte pour attirer les joueurs (ex: &quot;Gagnez un an de produits&quot;).</li><li><strong>Le Code Promo :</strong> Le lot de consolation (ex: &quot;Merci d&#39;avoir joué ! Voici -15%&quot;).</li><li><strong>Les Visuels :</strong> Packshots des lots et votre logo HD.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">2</div><div><h3>Mise en place (Côté Distributeur)</h3><p>Le Distributeur s&#39;occupe de la technique :</p><ul><li>Création d&#39;une <strong>Landing Page</strong> dédiée sur son site e-commerce.</li><li>Activation des leviers de trafic (Newsletter, Push Web, Bannières site) pour diriger ses clients vers le jeu.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">3</div><div><h3>Mécanique de collecte (Opt-in)</h3><p>Lors de l&#39;inscription au jeu, le participant coche une case spécifique :</p><div style="background:var(--vp-c-bg-elv);border:1px dashed var(--vp-c-divider);padding:10px;border-radius:4px;display:inline-block;"> ☑ <em>J&#39;accepte de recevoir les offres du partenaire [Nom de votre Marque].</em></div><p>C&#39;est cette case qui rend la donnée &quot;RGPD Compliant&quot; et monétisable.</p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-tint-green-text);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">⚡</div><div><h3>Transfert de Data &amp; Activation</h3><p>À la fin de la campagne (ou à fréquence définie) :</p><ol><li>Le Distributeur extrait la base des participants &quot;Opt-in&quot;.</li><li>Il vous transmet ce fichier sécurisé (CSV) via getinside.</li></ol><div style="border:1px solid var(--gi-tint-yellow-text);background:var(--gi-tint-yellow-bg);padding:15px;border-radius:6px;margin-top:15px;"><strong style="color:var(--gi-tint-yellow-text);">⚠️ Action Critique de votre part :</strong><br> Vous devez intégrer ces emails dans votre outil CRM (Mailchimp, Klaviyo...) et leur envoyer un email de bienvenue contenant <strong>le code promotionnel promis</strong>.<br><br><em>Le Timing est clé : Envoyez cet email le plus tôt possible après la fin du jeu pour maximiser le taux de conversion.</em></div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">5</div><div><h3>Tirage au sort</h3><p>Vous effectuez le tirage au sort des gagnants des gros lots et gérez l&#39;expédition des récompenses directement auprès d&#39;eux.</p></div></div>',8)])])}const v=t(s,[["render",n]]);export{g as __pageData,v as default};
